  }, "\uAC1D\uCCB4 \uB0B4\uBD80\uC758 \uAC12\uC744 \uBC14\uAFD4\uB3C4 \uAD1C\uCC2E\uC740\uC9C0, \uC544\uB2C8\uBA74 \uAC12\uC744 \uC77D\uAE30\uB9CC \uD574\uC57C \uD558\uB294 \uAC83\uC778\uC9C0?"), mdx("li", {
    parentName: "ol"
  }, "\uB300\uBD80\uBD84\uC758 \uB3D9\uAE30\uD654 \uC624\uB958\uB294 \uC774\uC640\uAC19\uC774 \uBA87\uAC00\uC9C0 \uC218\uCE59\uC744 \uC774\uD574\uD558\uC9C0 \uBABB\uD558\uACE0 \uD504\uB85C\uADF8\uB7A8\uC744 \uC791\uC131\uD558\uB294\uB370\uC11C \uC2F9\uD2B8\uAE30 \uC2DC\uC791\uD55C\uB2E4."), mdx("li", {
    parentName: "ol"
  }, "\uB610\uD55C, \uBC18\uB300\uB85C \uAC1D\uCCB4\uB97C \uC678\uBD80\uC5D0\uC11C \uC0AC\uC6A9\uD560 \uC218 \uC787\uB3C4\uB85D \uACF5\uAC1C\uD560 \uB54C\uC5D0\uB294 \uD574\uB2F9 \uAC1D\uCCB4\uB97C \uC5B4\uB5A4 \uBC29\uBC95\uC73C\uB85C \uC0AC\uC6A9\uD560 \uC218 \uC788\uACE0, \uC0AC\uC6A9\uD574\uC57C \uD558\uB294\uC9C0\uC5D0 \uB300\uD574\uC11C \uC815\uD655\uD558\uAC8C \uC124\uBA85\uD574\uC57C \uD55C\uB2E4.")), mdx("div", {
    "className": "gatsby-highlight",
    "data-language": "text"
  }, mdx("pre", {
    parentName: "div",
    "className": "language-text"
  }, mdx("code", {
    parentName: "pre",
    "className": "language-text"
  }, "\uC5EC\uB7EC \uC2A4\uB808\uB4DC\uB97C \uB3D9\uC2DC\uC5D0 \uC0AC\uC6A9\uD558\uB294 \uBCD1\uB82C \uD504\uB85C\uADF8\uB7A8\uC5D0\uC11C \uAC1D\uCCB4\uB97C \uACF5\uC720\uD574 \uC0AC\uC6A9\uD558\uACE0\uC790 \uD560 \uB54C \uAC00\uC7A5 \uB9CE\uC774 \uC0AC\uC6A9\uB418\uB294 \uBA87 \uAC00\uC9C0 \uC6D0\uCE59\uC744 \uC0B4\uD3B4\uBCF4\uBA74 \uB2E4\uC74C\uACFC \uAC19\uB2E4.\n\n[\uC2A4\uB808\uB4DC \uD55C\uC815] : \uC2A4\uB808\uB4DC\uC5D0 \uD55C\uC815\uB41C \uAC1D\uCCB4\uB294 \uC644\uC804\uD558\uAC8C \uD574\uB2F9 \uC2A4\uB808\uB4DC \uB0B4\uBD80\uC5D0 \uC874\uC7AC\uD558\uBA74\uC11C \uADF8 \uC2A4\uB808\uB4DC\uC5D0\uC11C\uB9CC \uD638\uCD9C\uD574 \uC0AC\uC6A9\uD560 \uC218 \uC788\uB2E4.\n[\uC77D\uAE30 \uC804\uC6A9 \uAC1D\uCCB4\uB97C \uACF5\uC720] : \uC77D\uAE30 \uC804\uC6A9 \uAC1D\uCCB4\uB97C \uACF5\uC720\uD574 \uC0AC\uC6A9\uD55C\uB2E4\uBA74 \uB3D9\uAE30\uD654 \uC791\uC5C5\uC744 \uD558\uC9C0 \uC54A\uB354\uB77C\uB3C4 \uC5EC\uB7EC \uC2A4\uB808\uB4DC\uC5D0\uC11C \uC5B8\uC81C\uB4E0\uC9C0 \uB9C8\uC74C\uAECF \uAC12\uC744 \uC77D\uC5B4 \uC0AC\uC6A9\uD560 \uC218 \uC788\uB2E4. \uBB3C\uB860 \uC77D\uAE30 \uC804\uC6A9 \uAC1D\uCCB4\uC5D0 \uD574\uB2F9\uD55C\uB2E4\uACE0 \uBCFC \uC218 \uC788\uB2E4.\n[\uC2A4\uB808\uB4DC\uC5D0 \uC548\uC804\uD55C \uAC1D\uCCB4\uB97C \uACF5\uC720] : \uC2A4\uB808\uB4DC\uC5D0 \uC548\uC804\uD55C \uAC1D\uCCB4\uB294 \uAC1D\uCCB4 \uB0B4\uBD80\uC801\uC73C\uB85C \uD544\uC218\uC801\uC778 \uB3D9\uAE30\uD654 \uAE30\uB2A5\uC774 \uB9CC\uB4E4\uC5B4\uC838 \uC788\uAE30 \uB54C\uBB38\uC5D0 \uC678\uBD80\uC5D0\uC11C \uB3D9\uAE30\uD654\uB97C \uC2E0\uACBD \uC4F8 \uD544\uC694\uAC00 \uC5C6\uACE0, \uC5EC\uB7EC \uC2A4\uB808\uB4DC\uC5D0\uC11C \uB9C8\uC74C\uAECF \uD638\uCD9C\uD574 \uC0AC\uC6A9\uD560 \uC218 \uC788\uB2E4.\n[\uB3D9\uAE30\uD654 \uBC29\uBC95 \uC801\uC6A9] : \uD2B9\uC815 \uAC1D\uCCB4\uC5D0 \uB3D9\uAE30\uD654 \uBC29\uBC95\uC744 \uC801\uC6A9\uD574\uB450\uBA74 \uC9C0\uC815\uD55C \uB77D\uC744 \uD68D\uB4DD\uD558\uAE30 \uC804\uC5D0\uB294 \uD574\uB2F9 \uAC1D\uCCB4\uB97C \uC0AC\uC6A9\uD560 \uC218 \uC5C6\uB2E4. \uC2A4\uB808\uB4DC\uC5D0 \uC548\uC804\uD55C \uAC1D\uCCB4 \uB0B4\uBD80\uC5D0\uC11C \uC0AC\uC6A9\uD558\uB294 \uAC1D\uCCB4\uB098 \uACF5\uAC1C\uB41C \uAC1D\uCCB4 \uAC00\uC6B4\uB370 \uD2B9\uC815 \uB77D\uC744 \uD655\uBCF4\uD574\uC57C \uC0AC\uC6A9\uD560 \uC218 \uC788\uB3C4\uB85D \uB9C9\uD600 \uC788\uB294 \uAC1D\uCCB4 \uB4F1\uC5D0 \uB3D9\uAE30\uD654 \uBC29\uBC95\uC774 \uC801\uC6A9\uB418\uC5B4 \uC788\uB2E4\uACE0 \uBCFC \uC218 \uC788\uB2E4."))), mdx("p", null, "\uCD9C\uCC98 :\uBE0C\uB77C\uC774\uC5B8 \uAD34\uCE20, \uB354\uADF8 \uB9AC, \uD300 \uD53C\uC5BC\uC2A4, \uC870\uC149 \uBCF4\uC6B0\uBE44\uC5B4, \uB370\uC774\uBE57 \uD648\uC988, \uC870\uC288\uC544 \uBE14\uB85C\uC26C \uACF5\uC800, \u300E \uBA40\uD2F0\uCF54\uC5B4\uB97C 100% \uD65C\uC6A9\uD558\uB294 \uC790\uBC14 \uBCD1\uB82C \uD504\uB85C\uADF8\uB798\uBC0D\u300F, \uC5D0\uC774\uCF58(2008.7.30), 3\uC7A5 \uC778\uC6A9."));
}
